-- ─── 1. 4-3-3 ───────────────────────────────────────────────
INSERT INTO formations (name, type, description, how_to_play, how_to_attack_against, how_to_defend_against, strengths, weaknesses, best_counter_formations, key_player_roles, famous_teams, radar_stats, player_positions)
VALUES (
  '4-3-3',
  '11',
  'Le 4-3-3 est l''une des formations les plus polyvalentes et offensivement ambitieuses du football moderne. Popularisé par l''Ajax d''Amsterdam dans les années 1970 puis perfectionné par la génération de Guardiola au Barça, ce système repose sur un triptyque offensif dévastateur combiné à un entrejeu dynamique capable de récupérer et de distribuer rapidement. La formation privilégie le pressing haut, la conservation du ballon et la verticalité dans les transitions.',
  'Le 4-3-3 fonctionne comme un organisme collectif où chaque ligne doit se coordonner parfaitement. En phase de possession, l''équipe cherche à créer une supériorité numérique dans le milieu de terrain grâce à des triangles permanents. Le milieu central (numéro 6) sert d''ancre défensive et de pivot de relance, tandis que les deux milieux relayeurs (numéros 8) apportent box-to-box dynamisme et appels entre les lignes. Les ailiers, placés très haut et larges, étirent la défense adverse et cherchent à rentrer dans l''axe sur leur pied dominant pour frapper au but ou jouer une combinaison rapide avec l''attaquant de pointe. Les latéraux ont un rôle crucial : ils montent haut pour créer des surnombres sur les flancs et peuvent même servir d''ailiers supplémentaires quand l''équipe est en possession. Le pressing est organisé par blocs : l''attaquant de pointe déclenche le pressing sur la relance adverse, les ailiers ferment les corridors vers les latéraux, et le milieu de récupération monte pour isoler le porteur du ballon.',
  'Pour attaquer efficacement contre un 4-3-3, l''objectif principal est d''exploiter l''espace laissé dans le dos des latéraux adverses, qui montent fréquemment pour participer à l''animation offensive. La stratégie la plus efficace consiste à jouer avec des ailiers rapides et directs qui se placent dans le couloir opposé au latéral adverse, prêts à recevoir des passes longues diagonales dès que celui-ci monte. Le changement de jeu rapide d''une aile à l''autre, effectué en 2 ou 3 passes maximum, est particulièrement dévastateur car le bloc défensif du 4-3-3 a tendance à se compresser du côté du ballon, laissant l''ailier adverse isolé sur le côté faible. Une deuxième approche consiste à saturer l''axe central en jouant deux attaquants ou un milieu offensif dans le dos du milieu de récupération adverse. Ce joueur clé du 4-3-3, même s''il est protecteur, peut être contourné par des passes en profondeur entre le pivot défensif et les centraux, notamment via un numéro 10 ou un second attaquant mobile. Les transitions rapides après récupération du ballon sont particulièrement dangereuses contre ce système : quand les latéraux et les milieux adverses sont montés, une récupération haute suivie de 2-3 passes directes peut créer des situations de 3 contre 3 ou 3 contre 2 face à la défense.',
  'Défendre contre un 4-3-3 nécessite d''abord de neutraliser les ailiers, points de départ de la quasi-totalité des offensives adverses. La priorité absolue est d''empêcher les ailiers de recevoir dos au but avec de l''espace devant eux : les latéraux doivent les suivre très haut et ne jamais leur laisser de temps pour se retourner. En bloc médian ou bas, il faut absolument fermer l''axe central et réduire les espaces entre les lignes pour empêcher les milieux relayeurs de recevoir entre les lignes. Une option efficace est d''utiliser un milieu en marquage sur le numéro 6 adverse pour priver le 4-3-3 de son pivot de relance. Quand le 4-3-3 perd le ballon, la meilleure réponse est une sortie rapide en profondeur avant que le pressing adverse se réorganise, car les 10-15 secondes suivant une perte de balle par le 4-3-3 sont un moment de vulnérabilité maximale. En set-plays défensifs, la ligne des 4 défenseurs doit rester coordonnée face aux appels croisés des ailiers et de l''avant-centre.',
  '["Pressing haut très efficace avec 3 attaquants", "Domination du milieu de terrain avec 3 joueurs", "Largeur de jeu maximale grâce aux ailiers", "Transition rapide attaque-défense", "Supériorité numérique sur les flancs quand les latéraux montent"]',
  '["Vulnérable aux contre-attaques dans l''espace laissé par les latéraux offensifs", "Le milieu à 3 peut être débordé par un milieu à 4", "Dépend beaucoup de la forme des ailiers", "Exige une condition physique élevée pour presser sur toute la hauteur du terrain", "Risque de déséquilibre défensif si les 8 ne rentrent pas vite"]',
  '["4-5-1", "4-4-2 défensif", "5-3-2"]',
  '{"GK": "Gardien actif dans la relance, capable de jouer au pied et de participer à la construction depuis derrière", "CB": "Défenseur central à l''aise balle au pied, capable de sortir proprement sous le pressing et d''éliminer un joueur par dribble", "LB": "Latéral offensif pur, capable de centrer des deux pieds et de rivaliser en 1v1 défensif malgré ses montées fréquentes", "RB": "Même profil que le latéral gauche : puissance athlétique pour les allers-retours répétés sur tout le couloir", "CDM": "Milieu de récupération, excellent dans les duels, intelligence de positionnement pour couvrir les espaces laissés par les 8", "CM-L": "Milieu relayeur box-to-box, percutant, capable de finir et de défendre haut", "CM-R": "Milieu relayeur box-to-box avec vision de jeu longue pour alimenter les ailiers", "LW": "Ailier gauche rentrant sur le pied droit, frappe de loin, dribble en 1v1", "RW": "Ailier droit rentrant sur le pied gauche, vitesse de pointe et percussion", "ST": "Avant-centre pivot capable de combiner, d''éliminer et de finir de la tête comme du pied"}',
  '["FC Barcelone (Guardiola, 2008-2012)", "Liverpool (Klopp, 2017-2024)", "Borussia Dortmund (Klopp, 2011-2015)", "Bayern Munich (Heynckes/Flick)", "Équipe de France (Deschamps, 2018-2021)"]',
  '{"attack": 82, "defense": 62, "pressing": 88, "possession": 78, "transition": 80}',
  '[{"id":"GK","label":"GB","x":0.5,"y":0.95},{"id":"RB","label":"DD","x":0.82,"y":0.78},{"id":"CB-R","label":"DC","x":0.65,"y":0.83},{"id":"CB-L","label":"DC","x":0.35,"y":0.83},{"id":"LB","label":"DG","x":0.18,"y":0.78},{"id":"CDM","label":"MDC","x":0.5,"y":0.65},{"id":"CM-R","label":"MR","x":0.68,"y":0.55},{"id":"CM-L","label":"ML","x":0.32,"y":0.55},{"id":"RW","label":"AD","x":0.82,"y":0.32},{"id":"LW","label":"AG","x":0.18,"y":0.32},{"id":"ST","label":"BU","x":0.5,"y":0.18}]'
);

-- ─── 2. 4-4-2 ───────────────────────────────────────────────
INSERT INTO formations (name, type, description, how_to_play, how_to_attack_against, how_to_defend_against, strengths, weaknesses, best_counter_formations, key_player_roles, famous_teams, radar_stats, player_positions)
VALUES (
  '4-4-2',
  '11',
  'Le 4-4-2 classique est la formation fondatrice du football anglais et l''une des plus équilibrées de l''histoire. Il repose sur deux blocs solides de quatre joueurs qui forment deux lignes compactes très difficiles à pénétrer. Ce système est idéal pour des équipes qui misent sur la solidité défensive, la discipline collective et les transitions rapides exploitant le duo d''attaquants. Sa lisibilité et sa robustesse en font une référence tactique intemporelle.',
  'Le 4-4-2 fonctionne sur deux principes fondamentaux : la compacité défensive et l''efficacité offensive. En phase de possession, les deux milieux centraux construisent le jeu avec une répartition claire des rôles — l''un plus défensif (qui couvre) et l''autre plus offensif (qui cherche à jouer entre les lignes ou arriver en soutien des attaquants). Les milieux latéraux courent les couloirs de bout en bout et fournissent des ballons aux deux attaquants dont la complémentarité est la clé du système : idéalement, un attaquant de fixation qui joue dos au but et un attaquant mobile qui se projette dans la profondeur. Le jeu en dehors, avec des centres et des remises en première touche, est l''arme principale. En phase défensive, le bloc de 8 (4+4) se forme immédiatement et réduit l''espace central en priorité.',
  'Le 4-4-2 classique présente une faille structurelle importante : l''espace entre la ligne des 4 milieux et la ligne des 4 défenseurs, appelé "l''entre-deux". Un numéro 10 ou un milieu offensif qui aime se positionner dans cet espace peut faire des dégâts considérables. La stratégie la plus efficace est d''utiliser un meneur de jeu capable de recevoir entre les lignes, de se retourner rapidement et de servir les attaquants ou de frapper. Une autre faiblesse est la zone au milieu de terrain : avec seulement 2 milieux centraux, créer une supériorité numérique à 3v2 dans l''axe crée des espaces pour jouer en triangle. Les largeurs sont également importantes : les milieux latéraux du 4-4-2 doivent défendre et attaquer, ce qui les fatigue. En fin de match ou après des courses intensives, les espaces derrière eux sur les flancs peuvent être exploités par des ailiers rapides.',
  'Le 4-4-2 est une formation naturellement solide qui se défend de lui-même grâce à sa double ligne compacte. Pour défendre face aux attaques adverses, la priorité est de maintenir le bloc compact et de ne jamais laisser de joueur adverse recevoir librement entre les lignes. Les milieux centraux doivent se parler constamment pour gérer les rotations quand l''adversaire surcharge un côté. Le piège classique à éviter : les milieux latéraux qui montent trop haut et reviennent en retard, laissant les défenseurs en infériorité. La meilleure défense du 4-4-2 reste son organisation collective : si les deux lignes restent à moins de 30-35 mètres l''une de l''autre, l''équipe adverse aura très peu d''espaces pour construire.',
  '["Solidité défensive remarquable grâce au double bloc", "Duo d''attaquants complémentaires très polyvalent", "Clarté des rôles — chaque joueur sait exactement ce qu''il doit faire", "Excellentes transitions rapides en contre-attaque", "Formation idéale pour les équipes moins techniques qui veulent être compactes"]',
  '["L''espace entre les deux lignes exploitable par un n°10", "Infériorité numérique au milieu face à un trio défensif (4-3-3, 4-2-3-1)", "Les milieux latéraux doivent énormément courir sur toute la longueur du terrain", "Manque de créativité si les deux milieux centraux sont trop défensifs", "Dépendance forte aux performances des deux attaquants"]',
  '["4-2-3-1", "4-3-3", "3-5-2"]',
  '{"GK": "Gardien communicatif qui organise la défense", "CB": "Défenseur central fort dans les duels aériens et au sol, solide dans les 1v1", "LB": "Latéral polyvalent capable de défendre et de monter pour centrer", "RB": "Même profil, plus offensif si le milieu droit est plus défensif", "CM-D": "Milieu défensif : récupérateur, couverture de l''espace, relance simple", "CM-O": "Milieu offensif : vision, passes décisives, arrivées dans la surface", "ML": "Milieu gauche : travailleur, capable de centrer et de défendre en 1v1", "MR": "Milieu droit : idem, souvent plus offensif pour créer des décalages", "ST-1": "Attaquant de fixation : fort physiquement, jeu de dos, remises pour le partenaire", "ST-2": "Attaquant mobile : vitesse, appels dans la profondeur, finition"}',
  '["AC Milan (Sacchi, 1988-1994)", "Manchester United (Ferguson, 1993-2013)", "Leicester City (Ranieri, 2015-2016)", "Chelsea (Mourinho, 2004-2006)", "Équipe de France (1998, Jacquet)"]',
  '{"attack": 70, "defense": 78, "pressing": 62, "possession": 65, "transition": 75}',
  '[{"id":"GK","label":"GB","x":0.5,"y":0.95},{"id":"RB","label":"DD","x":0.82,"y":0.78},{"id":"CB-R","label":"DC","x":0.65,"y":0.83},{"id":"CB-L","label":"DC","x":0.35,"y":0.83},{"id":"LB","label":"DG","x":0.18,"y":0.78},{"id":"MR","label":"MR","x":0.82,"y":0.58},{"id":"CM-D","label":"MC","x":0.62,"y":0.62},{"id":"CM-O","label":"MC","x":0.38,"y":0.62},{"id":"ML","label":"MG","x":0.18,"y":0.58},{"id":"ST-R","label":"BU","x":0.62,"y":0.22},{"id":"ST-L","label":"BU","x":0.38,"y":0.22}]'
);

-- ─── 3. 4-2-3-1 ─────────────────────────────────────────────
INSERT INTO formations (name, type, description, how_to_play, how_to_attack_against, how_to_defend_against, strengths, weaknesses, best_counter_formations, key_player_roles, famous_teams, radar_stats, player_positions)
VALUES (
  '4-2-3-1',
  '11',
  'Le 4-2-3-1 est la formation la plus répandue dans le football professionnel européen des années 2010-2020. Elle marie solidité défensive et créativité offensive grâce à un double pivot protecteur qui libère le trident offensif (meneur + ailiers). L''équilibre entre lignes en fait un choix privilégié des entraîneurs pragmatiques cherchant à ne pas prendre de risques en défense tout en ayant les ressources pour créer le déséquilibre vers l''avant.',
  'Le 4-2-3-1 s''articule autour du double pivot, colonne vertébrale du système. Ces deux milieux défensifs jouent en décalage : l''un sort pour presser ou dérober le ballon pendant que l''autre couvre l''espace laissé libre. Au-dessus d''eux, le meneur de jeu (n°10) est le chef d''orchestre : il reçoit entre les lignes, distribue aux ailiers, arrive en soutien de l''avant-centre ou déclenche lui-même. Les ailiers jouent très hauts et larges, tirent les latéraux adverses dans leurs couloirs pour créer des espaces dans l''axe. L''avant-centre — souvent un pivot de qualité — joue des remises et des déviations pour le meneur ou les milieux qui arrivent en soutien. En phase défensive, le 4-2-3-1 forme rapidement un bloc 4-4-2 (meneur + un attaquant, les ailiers devenant milieux latéraux) ou un 4-5-1 (les trois offensifs rejoignent les deux pivots).',
  'La clé pour attaquer contre un 4-2-3-1 est de trouver les espaces entre les couloirs de chaque côté du double pivot. Quand les deux pivots s''attirent vers le même côté, un écart se crée de l''autre côté de l''axe, exploitable par un milieu arrivant en retard ou par une combinaison rapide avec un ailier rentrant. Une autre stratégie gagnante est d''utiliser les largeurs : les ailiers adverses en 4-2-3-1 défendent souvent mal car ils sont positionnés très haut. Si on tire parti des flancs avec des latéraux offensifs qui centrent tôt et des attaquants capables d''attaquer les premiers ballons, le système montre ses limites. Enfin, une pression collective sur le double pivot peut être décisive : si les deux pivots sont perturbés dans leurs distributions, le 4-2-3-1 perd son équilibre et le meneur se retrouve isolé sans relais.',
  'Défendre contre le 4-2-3-1 nécessite de neutraliser le meneur de jeu, pivot de toutes les offensives. Il faut désigner un joueur pour lui coller dessus en permanence — soit un milieu défensif, soit une organisation collective qui l''empêche de se retourner. La deuxième priorité est de ne pas permettre aux ailiers de couper vers l''intérieur : les latéraux doivent les pousser vers la ligne de touche où ils sont moins dangereux. En phase de pression, il faut attaquer le double pivot vite avant qu''ils ne puissent se retourner : si on isole un pivot, il sera souvent en difficulté pour se sortir des pressing intenses. Créer un 3v2 dans l''axe en montant un milieu supplémentaire peut perturber toute l''organisation du 4-2-3-1.',
  '["Double pivot très sécurisant défensivement", "Le n°10 bénéficie de liberté totale pour créer", "Excellente couverture du terrain sur toute la largeur", "Très bonne gestion des transitions défensives", "Polyvalence : peut évoluer en 4-4-2 ou 4-5-1 défensif rapidement"]',
  '["Dépendance au n°10 — s''il est neutralisé, l''équipe perd son créateur", "Les ailiers doivent revenir défendre, ce qui limite leur impact offensif", "Le double pivot peut manquer de créativité et ralentir le jeu", "Avant-centre souvent isolé s''il n''est pas servi rapidement", "Moins efficace en possession pure face à une équipe qui presse haut"]',
  '["4-3-3 (pressing haut)", "3-5-2", "4-1-4-1"]',
  '{"GK": "Gardien organisateur, à l''aise pour relancer avec les pieds", "CB": "Défenseur central technique, capable de sortir proprement sous le pressing", "LB": "Latéral offensif avec bonne qualité de centre pour alimenter les ailiers", "RB": "Latéral droit dynamique qui monte en soutien de l''ailier", "CDM-1": "Premier pivot : récupérateur-destructor, duels, intervention pour protéger la défense", "CDM-2": "Deuxième pivot : meilleur techniquement, relance proprement et distribue", "CAM": "Meneur de jeu : le joueur le plus créatif, vision, dribble, passes décisives", "LW": "Ailier gauche : vitesse, percussion, rentrant", "RW": "Ailier droit : profil miroir, rentre sur le pied gauche", "ST": "Avant-centre : pivot ou mobile, charnière de toutes les combinaisons"}',
  '["Real Madrid (Ancelotti, 2003-2006)", "Allemagne (Löw, 2010-2014)", "Chelsea (Mourinho, 2006-2007)", "Atletico Madrid (Simeone)", "Manchester City (pré-Guardiola)"]',
  '{"attack": 76, "defense": 72, "pressing": 68, "possession": 80, "transition": 65}',
  '[{"id":"GK","label":"GB","x":0.5,"y":0.95},{"id":"RB","label":"DD","x":0.82,"y":0.78},{"id":"CB-R","label":"DC","x":0.65,"y":0.83},{"id":"CB-L","label":"DC","x":0.35,"y":0.83},{"id":"LB","label":"DG","x":0.18,"y":0.78},{"id":"CDM-R","label":"MDC","x":0.62,"y":0.67},{"id":"CDM-L","label":"MDC","x":0.38,"y":0.67},{"id":"RW","label":"AD","x":0.78,"y":0.45},{"id":"CAM","label":"MO","x":0.5,"y":0.45},{"id":"LW","label":"AG","x":0.22,"y":0.45},{"id":"ST","label":"BU","x":0.5,"y":0.18}]'
);

-- ─── 4. 4-5-1 ───────────────────────────────────────────────
INSERT INTO formations (name, type, description, how_to_play, how_to_attack_against, how_to_defend_against, strengths, weaknesses, best_counter_formations, key_player_roles, famous_teams, radar_stats, player_positions)
VALUES (
  '4-5-1',
  '11',
  'Le 4-5-1 est une formation défensive robuste qui sacrifie la présence offensive en faveur d''une compacité extrême au milieu de terrain. Avec cinq milieux qui forment une ligne hermétique, ce système vise à étouffer l''adversaire dans sa zone de création et à exploiter les espaces en contre-attaque via un avant-centre isolé mais très mobile. C''est la formation des équipes réalistes qui veulent tenir un résultat ou jouer contre des adversaires supérieurs techniquement.',
  'En possession, le 4-5-1 cherche à sortir rapidement de la pression adverse par des passes longues vers l''avant-centre, qui doit avoir les qualités pour garder le ballon, attirer des défenseurs et permettre aux milieux de monter. Une fois la transition effectuée, les ailiers-milieux se projettent vers l''avant pour créer un 4-3-3 ou 4-2-3-1 offensif temporaire. Défensivement, les cinq milieux se resserrent pour former un bloc compact qui couvre tout l''axe central sur une largeur de 40 mètres environ. Les deux milieux latéraux défendent comme des arrières supplémentaires mais doivent être capables de repartir vite vers l''avant pour alimenter le contre.',
  'La clé pour attaquer un 4-5-1 est la patience et la mobilité. La ligne de 5 milieux adverses peut être percée de plusieurs manières. D''abord, en jouant des passes courtes rapides pour forcer des ouvertures dans le bloc compact : quand un joueur adverse sort pour presser, un espace se crée dans son dos. Deuxièmement, les centres depuis les flancs sont très efficaces car les latéraux adverses sont souvent dépassés en profondeur quand les milieux latéraux montent trop haut. La troisième solution est le jeu par-dessus le bloc : des passes lobées vers un attaquant qui court dans le dos des défenseurs peuvent briser le bloc si ceux-ci ne sont pas bien synchronisés. Il faut surtout avoir de la patience et tolérer la possession sans progresser trop tôt.',
  'Le 4-5-1 se défend naturellement bien avec sa ligne de 5. La discipline est le mot-clé : chaque joueur doit rester dans sa zone et ne pas se laisser attirer hors de sa position. Le danger principal est le couloir laissé libre quand un milieu latéral monte trop haut. Si l''équipe adverse récupère le ballon dans ces conditions, elle dispose de 4 contre 3 ou 3 contre 2 en contre-attaque. La ligne de 5 doit donc avoir des règles strictes : dès que la possession est perdue, tout le monde rentre immédiatement. L''avant-centre doit être le premier défenseur sur la relance adverse pour gagner du temps.',
  '["Compacité défensive maximale avec 9 joueurs derrière le ballon", "Contre-attaques dévastatrices si les milieux sont rapides", "Très difficile à percer pour les équipes qui privilégient la possession", "Stabilité défensive qui fatigue les attaquants adverses", "Idéale pour tenir un résultat ou jouer contre des équipes supérieures"]',
  '["Manque flagrant de présence offensive avec un seul attaquant", "L''avant-centre est trop isolé et peut vite se décourager", "Peu de créativité — le jeu peut devenir prévisible défensivement", "Dépend de la qualité et de la vitesse des contre-attaques", "Formation difficile à tenir sur 90 minutes physiquement"]',
  '["4-3-3 (possession)", "3-4-3", "4-4-2"]',
  '{"GK": "Gardien solide dans les 1v1, excellent dans les interventions sur les centres", "CB": "Défenseurs centraux très forts dans les duels, notamment aériens", "LB": "Latéral défensif qui monte peu, priorité à la solidité", "RB": "Idem, discipline et capacité à défendre en 1v1 en priorité", "DM": "Milieu défensif central : pivot protecteur, intercepteur, relance simple", "CM-R": "Milieu droit : box-to-box, défend d''abord mais peut contre-attaquer", "CM-L": "Milieu gauche : idem, avec préférence pour les départs en transition", "ML": "Milieu latéral gauche : ailier défensif, vitesse pour le contre", "MR": "Milieu latéral droit : vitesse, centre, finisseur dans le couloir", "ST": "Avant-centre : forte personnalité, capable de tenir le ballon seul, mobile"}',
  '["Chelsea (Mourinho bloc bas)", "Atletico Madrid (Simeone, variante)", "Grèce (Euro 2004 — Rehhagel)", "Équipe d''Algérie (CAN 2019)", "Leicester défensif (certains matchs)"]',
  '{"attack": 52, "defense": 87, "pressing": 58, "possession": 60, "transition": 72}',
  '[{"id":"GK","label":"GB","x":0.5,"y":0.95},{"id":"RB","label":"DD","x":0.82,"y":0.78},{"id":"CB-R","label":"DC","x":0.65,"y":0.83},{"id":"CB-L","label":"DC","x":0.35,"y":0.83},{"id":"LB","label":"DG","x":0.18,"y":0.78},{"id":"MR","label":"MD","x":0.88,"y":0.55},{"id":"CM-R","label":"MC","x":0.68,"y":0.6},{"id":"DM","label":"MDC","x":0.5,"y":0.65},{"id":"CM-L","label":"MC","x":0.32,"y":0.6},{"id":"ML","label":"MG","x":0.12,"y":0.55},{"id":"ST","label":"BU","x":0.5,"y":0.18}]'
);

-- ─── 5. 3-5-2 ───────────────────────────────────────────────
INSERT INTO formations (name, type, description, how_to_play, how_to_attack_against, how_to_defend_against, strengths, weaknesses, best_counter_formations, key_player_roles, famous_teams, radar_stats, player_positions)
VALUES (
  '3-5-2',
  '11',
  'Le 3-5-2 est une formation ambitieuse qui tente de cumuler les avantages d''une défense à 3 centraux (solidité dans l''axe) avec la supériorité numérique au milieu de terrain (5 milieux). Les pistons (ou ailiers-milieux) sont au cœur du système : ils jouent à la fois le rôle de latéraux défensifs et d''ailiers offensifs, montant et descendant sans cesse sur toute la longueur du terrain. Ce système exige une discipline tactique et une condition physique exceptionnelles.',
  'En possession, le 3-5-2 cherche à construire proprement depuis les 3 défenseurs centraux qui se dispersent horizontalement pour créer des angles de passe. Les deux milieux défensifs gèrent le tempo et la sécurité pendant que le milieu offensif joue entre les lignes et combine avec les deux attaquants. Le duo d''attaquants fonctionne comme dans un 4-4-2 : un fixateur et un mobile. Les pistons constituent l''arme principale : quand l''adversaire est en place, ils créent des 2v1 sur les flancs avec les attaquants ou les milieux offensifs. En phase défensive, le 3-5-2 se transforme en 5-3-2 avec les pistons qui reculent pour former une ligne de 5.',
  'La faiblesse principale du 3-5-2 sont les espaces derrière les pistons quand ils sont montés haut. Si on récupère le ballon et qu''on joue vite dans le couloir opposé à celui où le piston adverse est monté, on se retrouve dans une situation de 1v1 ou 2v1 favorable face au défenseur central qui doit sortir. Des ailiers rapides qui jouent très larges peuvent étirer les défenseurs centraux et créer des espaces dans l''axe pour un attaquant ou un milieu. Une autre approche efficace est d''exploiter les zones de transition entre le piston adverse et le défenseur central de son côté : ces zones ne sont pas toujours clairement assignées et peuvent créer de la confusion.',
  'Défendre contre un 3-5-2 nécessite d''empêcher les pistons de prendre de la vitesse. Dès que le piston adverse a le ballon dans son couloir, il faut attaquer son couloir extérieur pour l''empêcher de centrer. En retraite défensive, les joueurs les plus proches de la touche adverse doivent harceler les pistons et les empêcher de se retrouver en situations de 1v1 confortables. La zone centrale étant très peuplée avec 5 milieux adverses, la solution est souvent d''étirer le jeu sur les flancs pour créer des espaces par jeu rapide de côté à côté.',
  '["Supériorité numérique garantie au milieu de terrain", "Solidité centrale avec 3 défenseurs centraux", "Les pistons créent une supériorité permanente sur les flancs", "Deux attaquants pour peser sur la défense", "Formation très flexible selon le profil des joueurs"]',
  '["Très exigeant physiquement pour les pistons (90m de course)", "Vulnérable si les pistons sont battus en 1v1 dans leur couloir", "Les défenseurs centraux excentrés doivent couvrir beaucoup d''espace", "Formation complexe à mettre en place tactiquement", "Risque en cas de perte de balle en transition si les pistons sont trop hauts"]',
  '["4-3-3 (largeur)", "4-5-1", "4-4-2"]',
  '{"GK": "Gardien organisateur, communication permanente avec les 3 centraux", "CB-C": "Défenseur central le plus fort dans les duels, libero du système", "CB-R": "Défenseur central droit : couverture de l''espace, remplace le piston en défense", "CB-L": "Défenseur central gauche : idem côté gauche", "WB-R": "Piston droit : le joueur le plus complet du terrain, ailier + latéral", "WB-L": "Piston gauche : même profil, préférence pour la jambe gauche", "CM-D": "Milieu défensif : pivot protecteur des 3 centraux", "CM-O": "Milieu offensif : liant entre la défense et l''attaque", "CAM": "Milieu relayeur : créatif, joue entre les lignes pour les 2 attaquants", "ST-1": "Attaquant de fixation : tient le ballon, aspire les défenseurs", "ST-2": "Attaquant mobile : runs dans la profondeur, finisseur"}',
  '["Juventus (Conte, 2011-2014)", "Inter Milan (Mourinho, 2009-2010)", "Chelsea (Conte, 2016-2018)", "Italie (Mancini, 2020-2021)", "Atlético Madrid (variante)"]',
  '{"attack": 72, "defense": 76, "pressing": 65, "possession": 70, "transition": 70}',
  '[{"id":"GK","label":"GB","x":0.5,"y":0.95},{"id":"CB-R","label":"DC","x":0.72,"y":0.83},{"id":"CB-C","label":"DC","x":0.5,"y":0.86},{"id":"CB-L","label":"DC","x":0.28,"y":0.83},{"id":"WB-R","label":"PD","x":0.88,"y":0.55},{"id":"CM-D","label":"MDC","x":0.62,"y":0.65},{"id":"CAM","label":"MO","x":0.5,"y":0.52},{"id":"CM-O","label":"MC","x":0.38,"y":0.65},{"id":"WB-L","label":"PG","x":0.12,"y":0.55},{"id":"ST-R","label":"BU","x":0.63,"y":0.22},{"id":"ST-L","label":"BU","x":0.37,"y":0.22}]'
