-- ─── 6. 3-4-3 ───────────────────────────────────────────────
INSERT INTO formations (name, type, description, how_to_play, how_to_attack_against, how_to_defend_against, strengths, weaknesses, best_counter_formations, key_player_roles, famous_teams, radar_stats, player_positions)
VALUES (
  '3-4-3',
  '11',
  'Le 3-4-3 est la formation la plus offensive de l''éventail tactique moderne. Avec trois défenseurs centraux et trois attaquants, elle offre une présence massive dans les deux zones décisives du terrain. Le milieu à 4, souvent composé de deux joueurs centraux et deux pistons, doit assurer la liaison et les transitions à toute vitesse. C''est une formation spectaculaire qui prend des risques calculés pour dominer les adversaires.',
  'En possession, le 3-4-3 cherche à saturer les zones avancées en permanence. Les trois attaquants restent hauts et larges pour créer de l''espace et des courses continues. Les pistons montent pour créer des supériorités sur les flancs, transformant le système en 3-2-5 en possession. Les deux milieux centraux gèrent la transition et ne doivent jamais se retrouver tous les deux au même endroit. En phase défensive, la priorité est une récupération ultra-haute pour ne jamais laisser l''adversaire construire. Si le pressing haut échoue, le 3-4-3 se replie rapidement en 5-4-1 avec les pistons qui défendent.',
  'Pour attaquer contre un 3-4-3, l''espace entre les trois défenseurs est crucial. Quand les pistons montent, des espaces apparaissent entre les centraux excentrés et le piston de leur côté. Un jeu rapide de 2-3 passes peut isoler un attaquant rapide contre un défenseur central en 1v1. Les contre-attaques sont également très efficaces : avec seulement 3 défenseurs et 2 milieux pour couvrir, une récupération haute suivie de transitions rapides crée facilement des situations 3v3 ou 4v3 face à la défense.',
  'Défendre contre un 3-4-3 exige une organisation défensive ultra-rigoureuse. Avec 3 attaquants adverses, chaque défenseur central doit être capable de défendre en 1v1 sans aide. La discipline dans le bloc défensif est primordiale : aucune sortie prématurée des centraux car les 3 attaquants adverses exploiteront immédiatement l''espace créé. En possession, jouer rapidement pour profiter des espaces laissés par les pistons et l''attaque adverse qui ne rentrent pas toujours assez vite.',
  '["Présence offensive maximale avec 3 attaquants permanents", "Pressing ultra-haut qui étouffe les adversaires dans leur zone", "Les pistons créent des supériorités sur les deux flancs simultanément", "Formation spectaculaire qui attire visuellement les espaces", "Excellente pour les équipes dominantes face à des adversaires inférieurs"]',
  '["Défense à 3 très vulnérable aux contre-attaques rapides", "Exige une condition physique et une rigueur tactique exceptionnelles des pistons", "Les deux milieux centraux sont en infériorité face à des milieux à 3 ou 4", "Si les pistons ne rentrent pas, la défense est en 3v3 permanente", "Formation difficile à maintenir sur 90 minutes contre des équipes bien organisées"]',
  '["4-5-1 défensif", "5-3-2", "4-4-2 compact"]',
  '{"GK": "Gardien très actif dans la construction, must jouer au pied", "CB-R": "Défenseur central droit : doit défendre en 1v1 régulièrement", "CB-C": "Libero central : le plus expérimenté, leader défensif", "CB-L": "Défenseur central gauche : couverture de l''ailier adverse", "WB-R": "Piston droit : le joueur le plus important du système — ailier + latéral", "WB-L": "Piston gauche : même exigence, qualité technique et athlétique de pointe", "CM-1": "Milieu central défensif : récupérateur qui filtre les transitions", "CM-2": "Milieu central offensif : liaison et créativité vers l''attaque", "RW": "Ailier droit : vitesse, dribble, finition, reste très haut", "LW": "Ailier gauche : miroir du droit, percussion", "ST": "Avant-centre : pivot de tout le système offensif, combine, finit"}',
  '["Chelsea (Tuchel, 2021)", "Manchester City (variante)", "Ajax (pré-Champions League)", "Belgique (Martinez)", "AS Roma (Mourinho, variante)"]',
  '{"attack": 88, "defense": 55, "pressing": 82, "possession": 68, "transition": 84}',
  '[{"id":"GK","label":"GB","x":0.5,"y":0.95},{"id":"CB-R","label":"DC","x":0.72,"y":0.83},{"id":"CB-C","label":"DC","x":0.5,"y":0.86},{"id":"CB-L","label":"DC","x":0.28,"y":0.83},{"id":"WB-R","label":"PD","x":0.88,"y":0.58},{"id":"CM-1","label":"MC","x":0.62,"y":0.62},{"id":"CM-2","label":"MC","x":0.38,"y":0.62},{"id":"WB-L","label":"PG","x":0.12,"y":0.58},{"id":"RW","label":"AD","x":0.78,"y":0.28},{"id":"ST","label":"BU","x":0.5,"y":0.18},{"id":"LW","label":"AG","x":0.22,"y":0.28}]'
);

-- ─── 7. 5-3-2 ───────────────────────────────────────────────
INSERT INTO formations (name, type, description, how_to_play, how_to_attack_against, how_to_defend_against, strengths, weaknesses, best_counter_formations, key_player_roles, famous_teams, radar_stats, player_positions)
VALUES (
  '5-3-2',
  '11',
  'Le 5-3-2 est la référence des formations défensives solides qui gardent les armes pour blesser en contre-attaque. Avec cinq défenseurs qui forment un mur hermétique dans leur zone, cette formation vise à annihiler tout danger dans la moitié de terrain défensive avant d''exploiter les espaces en contre avec un duo d''attaquants complémentaires. C''est le choix des équipes pragmatiques qui veulent sécuriser le résultat ou affronter des adversaires favoris.',
  'En phase défensive (prioritaire), les cinq défenseurs forment une ligne compacte et basse. Les deux pistons défendent à hauteur des latéraux, rendant la ligne de 5 très difficile à pénétrer de face. Le milieu de 3 se place devant la défense pour filtrer les passes et presser les milieux adverses. En possession, les pistons se transforment en ailiers et montent pour créer des situations 3v4 ou 4v4 en attaque. Le duo d''attaquants joue des combinaisons courtes en attendant que les pistons rejoignent l''attaque pour créer une supériorité numérique.',
  'La ligne de 5 du 5-3-2 semble imperméable, mais elle possède des failles exploitables. La première est le jeu entre la ligne de 5 défenseurs et le milieu de 3 : cet espace entre les deux lignes peut être occupé par un numéro 10 ou un milieu offensif qui reçoit librement. Une deuxième approche est de saturer les flancs : si on envoie deux attaquants sur le même piston adverse, il est en surcharge et doit choisir entre défendre le fond et laisser le centre libre. Les phases arrêtées (corners, coups francs) sont également très efficaces face à une équipe qui se concentre sur son organisation en mouvement.',
  'Avec 5 défenseurs, le 5-3-2 se défend de lui-même dans l''axe. Le danger vient des flancs et des espaces entre les lignes. Si l''adversaire cherche à jouer par-dessus le bloc avec des passes longues, les défenseurs centraux doivent être très forts dans les duels aériens. La communication entre les 5 défenseurs est primordiale pour éviter les sorties prématurées et les espaces dans la ligne.',
  '["Solidité défensive maximale — très difficile à percer de face", "5 joueurs en défense = protection contre les centres et les attaques de couloir", "Contre-attaques efficaces avec les pistons qui partent vite", "Formation idéale pour défendre un résultat en fin de match", "Psychologiquement rassurante pour les défenseurs"]',
  '["Manque de présence offensive — 2 attaquants peuvent être isolés", "Les 3 milieux sont en infériorité numérique face à des milieux à 4", "Peu de pressing : l''adversaire peut construire tranquillement", "Dépend beaucoup des performances des pistons à monter et descendre", "Formation prévisible défensivement"]',
  '["4-3-3 (possession)", "4-4-2 (transitions)", "3-4-3"]',
  '{"GK": "Gardien de haut niveau : distribution précise pour lancer les contre-attaques", "CB-C": "Défenseur central : libero du système, leader vocal et tactique", "CB-R": "Défenseur central droit : fort en 1v1 et dans les airs", "CB-L": "Défenseur central gauche : idem côté gauche", "WB-R": "Piston droit : athlète complet, défend comme un latéral, attaque comme un ailier", "WB-L": "Piston gauche : miroir du droit", "DM": "Milieu défensif : récupérateur qui couvre la défense à 5", "CM-1": "Milieu central : la box-to-box, lien entre défense et attaque", "CM-2": "Milieu offensif : créativité pour alimenter le duo d''attaquants", "ST-1": "Attaquant principal : finisseur, disponible pour les contre-attaques", "ST-2": "Second attaquant : mobile, capacité à tenir le ballon seul"}',
  '["Inter Milan (Benitez)", "Portugal (Euro 2016)", "Atlético Madrid (format défensif)", "Équipe de Simeone en phase de résultat", "Certaines équipes de Serie A italienne"]',
  '{"attack": 62, "defense": 90, "pressing": 48, "possession": 55, "transition": 68}',
  '[{"id":"GK","label":"GB","x":0.5,"y":0.95},{"id":"WB-R","label":"PD","x":0.88,"y":0.75},{"id":"CB-R","label":"DC","x":0.68,"y":0.82},{"id":"CB-C","label":"DC","x":0.5,"y":0.85},{"id":"CB-L","label":"DC","x":0.32,"y":0.82},{"id":"WB-L","label":"PG","x":0.12,"y":0.75},{"id":"CM-R","label":"MC","x":0.68,"y":0.6},{"id":"DM","label":"MDC","x":0.5,"y":0.65},{"id":"CM-L","label":"MC","x":0.32,"y":0.6},{"id":"ST-R","label":"BU","x":0.62,"y":0.22},{"id":"ST-L","label":"BU","x":0.38,"y":0.22}]'
);

-- ─── 8. 5-4-1 ───────────────────────────────────────────────
INSERT INTO formations (name, type, description, how_to_play, how_to_attack_against, how_to_defend_against, strengths, weaknesses, best_counter_formations, key_player_roles, famous_teams, radar_stats, player_positions)
VALUES (
  '5-4-1',
  '11',
  'Le 5-4-1 est la formation la plus défensive possible dans un système à 11 joueurs. Avec 9 joueurs systématiquement derrière le ballon, elle vise la solidité absolue et l''invulnérabilité dans la zone défensive. Elle est utilisée pour tenir un résultat, jouer des matchs retour après une victoire, ou affronter des équipes nettement supérieures. Son efficacité repose sur une discipline collective sans faille et un avant-centre courageux.',
  'Le 5-4-1 n''a pas vraiment de phase offensive structurée : il attend la récupération du ballon et cherche à sortir proprement pour permettre à l''avant-centre de créer quelque chose seul ou avec les milieux latéraux qui montent prudemment. En défense, le bloc de 4 milieux et 5 défenseurs forme un carré de 9 joueurs sur 30 mètres qui ne laisse aucun espace. La priorité absolue est de ne jamais permettre une frappe sans opposition dans la surface. L''avant-centre doit déclencher la pression sur la relance adverse pour ralentir l''avancée et donner le temps au bloc de s''organiser.',
  'Le 5-4-1 est extrêmement difficile à percer de manière frontale. La solution est de faire circuler le ballon rapidement pour fatiguer le bloc et trouver les rares espaces disponibles. Les changements de jeu rapides d''une aile à l''autre peuvent désorganiser une ligne de 9 qui peine à se déplacer collectivement à grande vitesse. Les situations de phase fixe (corners, coups francs) sont particulièrement efficaces car le 5-4-1 se concentre sur l''organisation dynamique et peut être pris par surprise sur des schémas élaborés. La répétition de tirs de l''extérieur de la surface peut également forcer des erreurs.',
  'La formation se défend d''elle-même. La discipline est le mot d''ordre : 9 joueurs derrière le ballon signifie aucune tentation d''aller chercher le duel ailleurs que dans la zone défensive. Les risques principaux sont les phases arrêtées adverses et la fatigue en fin de match qui peut créer des trous dans le bloc. Un seul but encaissé peut briser psychologiquement la formation.',
  '["Solidité défensive quasi absolue sur 90 minutes", "Très difficile à battre pour toute équipe, même supérieure", "Conservation d''énergie en défense profonde", "Idéal pour les matchs retour ou pour tenir un résultat mince", "Peu de risques de concéder des buts sur le jeu"]',
  '["Quasi aucune capacité offensive — dépend uniquement des coups de pied arrêtés ou erreurs adverses", "L''avant-centre est totalement isolé et peut décrocher mentalement", "Formation moralement difficile à maintenir pour les joueurs offensifs", "Si un but est concédé, l''équipe doit sortir et se retrouve exposée", "Faible pour le moral et l''attractivité du jeu"]',
  '["4-3-3 (possession prolongée)", "3-4-3", "4-4-2"]',
  '{"GK": "Gardien de sang-froid, excellent réflexe, leader vocal de la défense", "CB-C": "Libero : le patron de la défense, organisateur permanent", "CB-R/L": "Défenseurs centraux latéraux : forts en 1v1, sans prise de risque", "WB-R/L": "Pistons : défendent comme des latéraux, montent rarement", "MR/ML": "Milieux latéraux : courent tout le match pour bloquer les couloirs", "CM-R/L": "Milieux centraux : récupérateurs, relance simple et directe", "ST": "Avant-centre guerrier : courage, ténacité, capable de tenir le ballon seul sur de longues périodes"}',
  '["Équipes en déplacement contre le top 6", "Leicester sur de grands matchs", "Grèce (Euro 2004 en finale)", "Atlético Madrid dans certains matchs de C1 en déplacement", "Équipes promues jouant le maintien"]',
  '{"attack": 48, "defense": 95, "pressing": 42, "possession": 50, "transition": 58}',
  '[{"id":"GK","label":"GB","x":0.5,"y":0.95},{"id":"WB-R","label":"PD","x":0.88,"y":0.75},{"id":"CB-R","label":"DC","x":0.68,"y":0.82},{"id":"CB-C","label":"DC","x":0.5,"y":0.85},{"id":"CB-L","label":"DC","x":0.32,"y":0.82},{"id":"WB-L","label":"PG","x":0.12,"y":0.75},{"id":"MR","label":"MD","x":0.78,"y":0.58},{"id":"CM-R","label":"MC","x":0.62,"y":0.62},{"id":"CM-L","label":"MC","x":0.38,"y":0.62},{"id":"ML","label":"MG","x":0.22,"y":0.58},{"id":"ST","label":"BU","x":0.5,"y":0.2}]'
);

-- ─── 9. 4-1-4-1 ─────────────────────────────────────────────
INSERT INTO formations (name, type, description, how_to_play, how_to_attack_against, how_to_defend_against, strengths, weaknesses, best_counter_formations, key_player_roles, famous_teams, radar_stats, player_positions)
VALUES (
  '4-1-4-1',
  '11',
  'Le 4-1-4-1 est une variante du 4-4-2 et du 4-5-1 qui place un seul milieu défensif devant la défense pour protéger l''axe central. La ligne de 4 milieux est très haute et proactive en possession, créant un système hybride capable de basculer entre une défense solide et une attaque organisée selon l''état du match. Le pivot défensif est la pièce maîtresse de ce système.',
  'Le milieu défensif isolé est le véritable chef d''orchestre du 4-1-4-1. Il doit être capable de récupérer les ballons perdus par la ligne de 4 milieux qui joue haut, de distribuer proprement vers les milieux offensifs et de couvrir les espaces laissés par les latéraux qui montent. La ligne de 4 milieux joue très haut et crée des situations de 4v4 ou 4v3 dans la zone de création adverse. L''avant-centre travaille entre les lignes ou en profondeur selon le profil. En phase défensive, les 4 milieux reculent pour former un bloc 4-4-1-1 ou 4-5-1 avec le seul pivot devant.',
  'La faiblesse du 4-1-4-1 est l''espace laissé entre le pivot et les 4 milieux quand ces derniers montent. Un numéro 10 ou un milieu relayeur qui arrive dans cet espace peut recevoir sans opposition et créer immédiatement le danger. Pour exploiter cela, il faut un joueur capable de courir dans l''espace entre les lignes et de tourner rapidement. Les centrales adverses sont aussi exploitables si le pivot adverse est isolé : une surcharge 2v1 sur lui peut le forcer à laisser passer le ballon.',
  'En défense contre ce système, il faut identifier rapidement quand la ligne de 4 milieux monte trop haut et exploiter ces moments de transition. La récupération du ballon dans la moitié adverse doit être suivie d''un jeu direct en profondeur avant que la ligne ne revienne. Le pivot adverse peut être contourné par des passes lobées légèrement devant lui.',
  '["Protection de l''axe défensif excellente grâce au pivot isolé", "La ligne de 4 milieux haute crée de nombreuses occasions", "Excellent pressing collectif organisé sur deux lignes", "Flexibilité pour basculer entre différents états du match", "Efficace pour contrôler le milieu de terrain face à des 4-4-2"]',
  '["Le pivot seul peut être surchargé en 2v1", "Espace entre le pivot et la ligne de 4 milieux exploitable", "Moins créatif offensivement que le 4-2-3-1", "L''avant-centre peut être isolé si la transition n''est pas rapide", "Exige un pivot de classe mondiale pour fonctionner au top niveau"]',
  '["4-3-3", "3-5-2", "4-2-3-1"]',
  '{"GK": "Gardien actif dans la relance pour le pivot", "CB": "Défenseurs centraux solides qui couvrent le pivot en cas de dépassement", "LB": "Latéral offensif : monte régulièrement pour créer des surnombres", "RB": "Idem côté droit", "CDM": "LE pivot — le joueur le plus important : technique, puissance, vision, duels", "CM-L": "Milieu gauche : box-to-box, travail défensif et offensif", "CM-R": "Milieu droit : idem", "ML": "Milieu latéral gauche : créativité, centres, finition", "MR": "Milieu latéral droit : percussion et profondeur", "ST": "Avant-centre : profil complet pour jouer seul en pointe"}',
  '["Arsenal (Wenger, variante)", "France (Zidane era)", "Espagne (possessionnel)", "Liverpool (époque Benitez)", "AC Milan (années 2000)"]',
  '{"attack": 62, "defense": 78, "pressing": 72, "possession": 76, "transition": 62}',
  '[{"id":"GK","label":"GB","x":0.5,"y":0.95},{"id":"RB","label":"DD","x":0.82,"y":0.78},{"id":"CB-R","label":"DC","x":0.65,"y":0.83},{"id":"CB-L","label":"DC","x":0.35,"y":0.83},{"id":"LB","label":"DG","x":0.18,"y":0.78},{"id":"CDM","label":"MDC","x":0.5,"y":0.68},{"id":"MR","label":"MD","x":0.78,"y":0.52},{"id":"CM-R","label":"MC","x":0.62,"y":0.56},{"id":"CM-L","label":"MC","x":0.38,"y":0.56},{"id":"ML","label":"MG","x":0.22,"y":0.52},{"id":"ST","label":"BU","x":0.5,"y":0.18}]'
);

-- ─── 10. 4-3-3 Pressing Haut ────────────────────────────────
INSERT INTO formations (name, type, description, how_to_play, how_to_attack_against, how_to_defend_against, strengths, weaknesses, best_counter_formations, key_player_roles, famous_teams, radar_stats, player_positions)
VALUES (
  '4-3-3 Pressing',
  '11',
  'Le 4-3-3 Pressing Haut, popularisé par Jürgen Klopp à Dortmund et Liverpool, pousse le principe du pressing à son paroxysme. L''équipe défend dans la moitié adverse, avec le trio offensif qui déclenche l''intense pression sur la relance adversaire dès la récupération du gardien. L''objectif est de forcer des erreurs dans les zones avancées et de transformer chaque perte de balle adverse en occasion de but immédiate. Cette "gegenpressing" (contre-pressing instantané) est l''un des systèmes les plus électriques et spectaculaires du football contemporain.',
  'Le pressing haut n''est pas seulement une phase défensive — c''est un mode d''attaque à part entière. Dès que l''adversaire a le ballon dans sa moitié de terrain, l''attaquant de pointe déclenche la pression en coupant les options de passe du gardien ou du défenseur central, forçant un long dégagement. Les ailiers harcèlent les défenseurs centraux latéraux tandis que les milieux relayeurs pressent les milieux adverses. L''objectif est de récupérer le ballon dans une zone avancée, à 30-40 mètres du but adverse. Une fois la récupération effectuée, la transition est immédiate : passe directe vers un attaquant qui reçoit dans une situation avantageuse face au but. Toute l''équipe doit être synchronisée car un pressing raté laisse un espace énorme dans le dos de la ligne haute.',
  'Le talon d''Achille du 4-3-3 pressing haut est le jeu long. Si l''adversaire arrive à passer au-dessus du pressing (par des passes longues lobées vers un attaquant rapide ou un milieu), l''espace laissé dans le dos de la défense haute est immense. Un attaquant de vitesse, un milieu qui fait une course en profondeur au moment du pressing ou un changement de jeu rapide peut instantanément placer l''équipe qui presse en situation de danger. Pour maximiser cette stratégie, il faut un avant-centre très véloce capable de courir dans le dos des 4 défenseurs adverses qui restent haut. Les équipes qui maîtrisent les passes longues précises et rapides vers un cible en profondeur font systématiquement souffrir le pressing haut.',
  'Défendre contre le pressing haut du 4-3-3 est un défi technique autant que mental. La solution principale est la qualité de la relance sous pression : les défenseurs doivent être capables de jouer vite et précisément quand ils sont pressés. Un gardien qui joue au pied est indispensable car il peut souvent trouver un joueur libre qui échappe au pressing. La deuxième solution est le jeu long maîtrisé : un défenseur central qui envoie un long ballon précis vers un attaquant de grande taille ou vers un ailier rapide peut neutraliser tout le pressing en une touche. Les pressing traps (fausses sorties pour attirer le presseur puis jouer dans l''espace) sont également très efficaces.',
  '["Récupération haute du ballon → occasions immédiates de but", "Pression psychologique permanente sur la défense adverse", "Football spectaculaire et intense qui démoralise les adversaires", "Transitions ultra-rapides qui ne laissent pas le temps à l''adversaire de s''organiser", "Idéal pour les équipes avec des joueurs très athlétiques et polyvalents"]',
  '["Exige une condition physique de très haut niveau (10-12 km par match)", "Si un pressing raté, l''équipe est exposée à des contre-attaques dévastatrices", "Difficile à maintenir sur 90 minutes — s''épuise en fin de match", "Vulnérable aux équipes qui maîtrisent le jeu long précis", "Exige une synchronisation parfaite — une erreur peut coûter cher"]',
  '["5-4-1 (bloc bas)", "4-5-1 défensif", "3-5-2 (transition rapide)"]',
  '{"GK": "Gardien très actif au pied, participe à la relance et déclenche les contre-pressing", "CB": "Défenseurs centraux très hauts : défense en 1v1 obligatoire, excellente vitesse", "LB": "Latéral gauche : monte jusqu''à la mi-terrain pour presser les latéraux adverses", "RB": "Idem côté droit", "CDM": "Milieu récupérateur : déclenche le contre-pressing immédiatement à chaque perte de balle", "CM-L": "Milieu relayeur : 12+ km par match, presse et attaque alternativement", "CM-R": "Idem côté droit", "LW": "Ailier gauche : premier presseur sur le défenseur central adverse droit", "RW": "Ailier droit : premier presseur sur le défenseur central adverse gauche", "ST": "Avant-centre : déclencheur du pressing sur le gardien ou le défenseur central le plus haut"}',
  '["Liverpool (Klopp, 2015-2024)", "Borussia Dortmund (Klopp, 2008-2015)", "RB Leipzig (Nagelsmann)", "Brighton (De Zerbi)", "Bayer Leverkusen (Xabi Alonso)"]',
  '{"attack": 85, "defense": 60, "pressing": 96, "possession": 70, "transition": 88}',
  '[{"id":"GK","label":"GB","x":0.5,"y":0.95},{"id":"RB","label":"DD","x":0.82,"y":0.75},{"id":"CB-R","label":"DC","x":0.64,"y":0.8},{"id":"CB-L","label":"DC","x":0.36,"y":0.8},{"id":"LB","label":"DG","x":0.18,"y":0.75},{"id":"CDM","label":"MDC","x":0.5,"y":0.62},{"id":"CM-R","label":"MR","x":0.68,"y":0.52},{"id":"CM-L","label":"ML","x":0.32,"y":0.52},{"id":"RW","label":"AD","x":0.82,"y":0.28},{"id":"LW","label":"AG","x":0.18,"y":0.28},{"id":"ST","label":"BU","x":0.5,"y":0.15}]'
