-- ─── 11. 3-3-1 ───────────────────────────────────────────────
INSERT INTO formations (name, type, description, how_to_play, how_to_attack_against, how_to_defend_against, strengths, weaknesses, best_counter_formations, key_player_roles, famous_teams, radar_stats, player_positions)
VALUES (
  '3-3-1',
  '8',
  'Le 3-3-1 est la formation la plus équilibrée du football à 8. Avec 3 défenseurs, 3 milieux et 1 attaquant, elle offre une couverture défensive solide tout en maintenant une présence offensive via un attaquant de pointe soutenu par le milieu. Idéale pour les équipes jeunes qui apprennent les principes tactiques, c''est une formation pédagogique qui enseigne les concepts fondamentaux du positionnement et de la compacité.',
  'En possession, les 3 milieux jouent en triangle pour créer des angles de passe permanents. Le milieu central gère la construction et la transition pendant que les deux milieux latéraux cherchent à déborder et centrer pour l''attaquant. Les 3 défenseurs restent groupés pour protéger le gardien, le central servant parfois de libero qui relance proprement. L''attaquant de pointe joue haut et cherche à provoquer les défenseurs adverses pour créer des espaces pour les milieux.',
  'Pour attaquer un 3-3-1, les espaces sur les flancs sont prioritaires. Avec 3 défenseurs qui ne peuvent pas tous les deux couvrir les couloirs, un milieu latéral rapide qui déborde crée immédiatement un 1v1 ou 2v1 dans le couloir. Les passes en profondeur entre les défenseurs centraux et latéraux adverses sont également très efficaces si l''attaquant fait un appel bien chronométré.',
  'La ligne de 3 défenseurs du 3-3-1 est relativement solide mais vulnérable si les milieux ne reviennent pas. La discipline des milieux est clé : dès que l''équipe perd le ballon, au moins un milieu doit redescendre pour aider les défenseurs et éviter les situations de 2v3 défensives.',
  '["Formation pédagogique idéale pour les jeunes joueurs", "Équilibre offensif-défensif raisonnable", "Le triangle de milieux crée de la fluidité dans la circulation", "Compacité naturelle avec les deux blocs proches", "Adaptable selon les profils des joueurs disponibles"]',
  '["Un seul attaquant peut être isolé et découragé", "Les flancs sont souvent peu couverts en défense", "Manque de puissance offensive face à des équipes à 2 attaquants", "Les milieux latéraux doivent courir beaucoup pour couvrir tout le terrain", "Peu de créativité si le milieu central n''est pas de qualité"]',
  '["3-2-2", "2-3-2", "4-2-1"]',
  '{"GK": "Gardien actif, communique avec les 3 défenseurs", "CB-C": "Défenseur central : leader défensif, relance proprement", "CB-R": "Défenseur droit : défend le couloir droit", "CB-L": "Défenseur gauche : idem côté gauche", "CM": "Milieu central : pivot du jeu, récupérateur et distributeur", "ML": "Milieu gauche : latéral offensif potentiel", "MR": "Milieu droit : offensif quand l''équipe est en possession", "ST": "Attaquant : mobilité, dribble, finition — doit tout faire seul"}',
  '["Catégories U11-U13 en France", "Équipes débutantes", "Clubs formateurs avec peu d''effectif"]',
  '{"attack": 72, "defense": 70, "pressing": 65, "possession": 68, "transition": 72}',
  '[{"id":"GK","label":"GB","x":0.5,"y":0.95},{"id":"CB-R","label":"DD","x":0.75,"y":0.8},{"id":"CB-C","label":"DC","x":0.5,"y":0.84},{"id":"CB-L","label":"DG","x":0.25,"y":0.8},{"id":"MR","label":"MD","x":0.75,"y":0.55},{"id":"CM","label":"MC","x":0.5,"y":0.58},{"id":"ML","label":"MG","x":0.25,"y":0.55},{"id":"ST","label":"BU","x":0.5,"y":0.18}]'
);

-- ─── 12. 3-2-2 ───────────────────────────────────────────────
INSERT INTO formations (name, type, description, how_to_play, how_to_attack_against, how_to_defend_against, strengths, weaknesses, best_counter_formations, key_player_roles, famous_teams, radar_stats, player_positions)
VALUES (
  '3-2-2',
  '8',
  'Le 3-2-2 est une formation en losange adaptée au football à 8 qui cherche à créer des supériorités offensives grâce à un double attaquant. Avec 3 défenseurs, 2 milieux compacts et 2 attaquants, cette formation vise un équilibre entre solidité et efficacité offensive. Les deux attaquants peuvent se combiner et créer des situations de 2v3 qui perturbent les défenses.',
  'Les 2 milieux jouent très serrés pour protéger les 3 défenseurs et relancer vers les 2 attaquants. En possession, ils cherchent à jouer rapidement pour les deux attaquants qui se combinent en permanence. Les 3 défenseurs restent compacts mais le défenseur central peut monter pour créer des situations de 3v2 au milieu. Les 2 attaquants fonctionnent sur le principe fixateur-mobile : l''un retient les défenseurs, l''autre court dans les espaces.',
  'Pour attaquer contre un 3-2-2, l''espace au milieu est relativement vide avec seulement 2 milieux adverses. Créer un 3v2 au milieu de terrain avec un milieu supplémentaire qui monte peut créer des occasions importantes. Les flancs sont également très ouverts car les 3 défenseurs doivent tous rester dans l''axe, laissant les couloirs libres.',
  'Avec 2 milieux seulement, le milieu de terrain est très compact mais peut être surchargé. La priorité est de garder les 2 milieux proches et disciplinés, ne jamais se laisser attirer vers le haut simultanément. Les 3 défenseurs doivent communiquer clairement pour se répartir les zones de couverture.',
  '["Double attaquant : pression permanente sur la défense adverse", "Milieu compact et difficile à pénétrer en axe", "Nombreuses combinaisons possibles entre les 2 attaquants", "Formation simple à comprendre pour les jeunes joueurs", "Efficace contre les équipes à 1 seul attaquant"]',
  '["Milieu à 2 peut être débordé en infériorité numérique", "Les flancs sont ouverts en défense", "Les 2 attaquants peuvent être coupés du jeu si le milieu est dominé", "Dépend beaucoup de la qualité du duo d''attaquants", "Manque de présence sur les couloirs offensifs"]',
  '["3-3-1", "4-2-1", "3-1-3"]',
  '{"GK": "Gardien actif dans la relance", "CB-C": "Défenseur central : leader défensif", "CB-R": "Défenseur droit", "CB-L": "Défenseur gauche", "CM-R": "Milieu droit : compact, peut monter en soutien des attaquants", "CM-L": "Milieu gauche : récupérateur en priorité", "ST-R": "Attaquant droit : fixateur ou mobile selon la configuration", "ST-L": "Attaquant gauche : complémentaire du partenaire"}',
  '["Catégories jeunes U10-U12 offensives", "Équipes avec 2 bons buteurs", "Football récréatif"]',
  '{"attack": 78, "defense": 65, "pressing": 62, "possession": 68, "transition": 75}',
  '[{"id":"GK","label":"GB","x":0.5,"y":0.95},{"id":"CB-R","label":"DD","x":0.75,"y":0.8},{"id":"CB-C","label":"DC","x":0.5,"y":0.84},{"id":"CB-L","label":"DG","x":0.25,"y":0.8},{"id":"CM-R","label":"MD","x":0.65,"y":0.55},{"id":"CM-L","label":"MG","x":0.35,"y":0.55},{"id":"ST-R","label":"BU","x":0.65,"y":0.2},{"id":"ST-L","label":"BU","x":0.35,"y":0.2}]'
);

-- ─── 13. 2-3-2 ───────────────────────────────────────────────
INSERT INTO formations (name, type, description, how_to_play, how_to_attack_against, how_to_defend_against, strengths, weaknesses, best_counter_formations, key_player_roles, famous_teams, radar_stats, player_positions)
VALUES (
  '2-3-2',
  '8',
  'Le 2-3-2 est la formation la plus offensive du football à 8. Avec seulement 2 défenseurs et un milieu de 3 très haut, elle maximise la présence dans la zone adverse mais s''expose à des contre-attaques dévastatrices. Ce système est idéal pour les équipes dominantes qui cherchent à écraser l''adversaire dès le coup d''envoi, avec une mentalité "on marque plus qu''eux".',
  'Les 3 milieux jouent très haut et créent des situations de supériorité numérique dans la zone de création adverse. Les 2 attaquants restent dans la surface adverse et cherchent les passes décisives des milieux. Les 2 défenseurs doivent être des joueurs d''expérience capables de défendre en 1v1 car ils seront régulièrement en infériorité numérique. Le jeu doit être rapide et vertical pour ne pas laisser l''adversaire s''organiser.',
  'Pour attaquer contre un 2-3-2, l''espace derrière les 3 milieux adverses est immense quand ils sont montés. Une transition rapide sur récupération de balle, avec une passe en profondeur vers un attaquant rapide, crée immédiatement un 2v2 ou 2v1 face aux 2 seuls défenseurs. Les contre-attaques sont la meilleure arme face à ce système.',
  'Défendre contre un 2-3-2 avec seulement 2 défenseurs est le plus grand défi tactique du football à 8. Les 2 défenseurs doivent rester dans leur zone, ne jamais sortir ensemble, et compter sur l''aide des milieux pour revenir défendre. La communication et la couverture mutuelle sont essentielles.',
  '["Présence offensive maximale avec 5 joueurs dans la moitié adverse", "Pression constante sur la défense adverse", "Très difficile à défendre pour les équipes qui ne sont pas préparées", "Football attractif et spectaculaire", "Idéal pour finir les matchs quand on est mené"]',
  '["Défense à 2 très vulnérable aux contre-attaques", "Les 2 défenseurs sont souvent en infériorité numérique", "Formation psychologiquement stressante pour les défenseurs", "Si on concède rapidement, difficile de réorganiser", "Exige une condition physique et une technique très élevées"]',
  '["3-3-1 défensif", "4-2-1", "3-2-2"]',
  '{"GK": "Gardien de haut niveau : doit compenser les failles défensives", "CB-R": "Défenseur droit : expérimenté, calme, fort en 1v1", "CB-L": "Défenseur gauche : idem, communication permanente avec son partenaire", "MR": "Milieu droit : offensif, monte et revient rapidement", "MC": "Milieu central : pivot du jeu, lien entre défense et attaque", "ML": "Milieu gauche : offensif, appels dans la profondeur", "ST-R": "Attaquant droit : finisseur dans la surface", "ST-L": "Attaquant gauche : mobile, fait le travail de fixation"}',
  '["Équipes jeunes très talentueuses", "U13-U15 offensives", "Football récréatif entre amateurs de haut niveau"]',
  '{"attack": 85, "defense": 55, "pressing": 80, "possession": 65, "transition": 82}',
  '[{"id":"GK","label":"GB","x":0.5,"y":0.95},{"id":"CB-R","label":"DD","x":0.68,"y":0.82},{"id":"CB-L","label":"DG","x":0.32,"y":0.82},{"id":"MR","label":"MD","x":0.78,"y":0.55},{"id":"MC","label":"MC","x":0.5,"y":0.52},{"id":"ML","label":"MG","x":0.22,"y":0.55},{"id":"ST-R","label":"BU","x":0.65,"y":0.2},{"id":"ST-L","label":"BU","x":0.35,"y":0.2}]'
);

-- ─── 14. 4-2-1 ───────────────────────────────────────────────
INSERT INTO formations (name, type, description, how_to_play, how_to_attack_against, how_to_defend_against, strengths, weaknesses, best_counter_formations, key_player_roles, famous_teams, radar_stats, player_positions)
VALUES (
  '4-2-1',
  '8',
  'Le 4-2-1 est la formation défensive par excellence du football à 8. Avec 4 défenseurs, 2 milieux compacts et 1 seul attaquant, elle crée un bloc de 6 joueurs derrière le ballon qui est extrêmement difficile à pénétrer. C''est la formation des équipes réalistes qui veulent minimiser les risques et miser sur les phases fixes ou les contre-attaques.',
  'Les 4 défenseurs forment une ligne très compacte qui laisse très peu d''espace entre les lignes. Les 2 milieux couvrent l''espace devant les défenseurs et récupèrent les ballons perdus. L''unique attaquant doit être capable de tenir le ballon seul pendant que les milieux montent en soutien, créant temporairement un 3-2-2 offensif. En phase de possession, le jeu doit être rapide et efficace car l''effectif offensif est réduit.',
  'Le 4-2-1 présente des failles similaires au 5-4-1 en football à 11. L''espace entre le milieu de 2 et la ligne de 4 défenseurs peut être exploité par un meneur de jeu capable de se retourner rapidement. Saturating les flancs avec des joueurs rapides peut étirer la ligne de 4 et créer des espaces dans l''axe.',
  'Le 4-2-1 se défend naturellement très bien grâce à sa ligne de 4 défenseurs. La discipline est primordiale : chaque défenseur doit rester dans sa zone et ne pas se laisser attirer. Le danger principal vient des phases arrêtées adverses.',
  '["Solidité défensive maximale pour le football à 8", "Ligne de 4 défenseurs — très difficile à pénétrer de face", "Idéal pour les équipes en infériorité technique", "Psychologiquement rassurant pour les défenseurs", "Efficace pour tenir un résultat"]',
  '["Un seul attaquant totalement isolé", "Peu de menace offensive — l''adversaire peut défendre haut", "Formation peu attractive à jouer pour les attaquants", "Dépend uniquement des phases arrêtées ou erreurs adverses", "Peut devenir monotone et démotivant pour les joueurs"]',
  '["2-3-2", "3-3-1 offensif", "3-2-2"]',
  '{"GK": "Gardien solide dans les 1v1 — indispensable", "CB-R": "Défenseur droit : fort physiquement", "CB-RC": "Défenseur central droit : axe central sécurisé", "CB-LC": "Défenseur central gauche : leader vocal", "CB-L": "Défenseur gauche : bon dans les duels", "CM-R": "Milieu droit : récupérateur, relance directe", "CM-L": "Milieu gauche : idem, légèrement plus créatif", "ST": "Attaquant : guerrier, capable de tout faire seul pendant 90 minutes"}',
  '["Équipes défensives jeunes", "Football à 8 compétitif — fin de championnat", "Équipes en déplacement contre favorites"]',
  '{"attack": 55, "defense": 85, "pressing": 55, "possession": 58, "transition": 62}',
  '[{"id":"GK","label":"GB","x":0.5,"y":0.95},{"id":"CB-R","label":"DD","x":0.82,"y":0.8},{"id":"CB-RC","label":"DC","x":0.6,"y":0.83},{"id":"CB-LC","label":"DC","x":0.4,"y":0.83},{"id":"CB-L","label":"DG","x":0.18,"y":0.8},{"id":"CM-R","label":"MD","x":0.65,"y":0.58},{"id":"CM-L","label":"MG","x":0.35,"y":0.58},{"id":"ST","label":"BU","x":0.5,"y":0.2}]'
);

-- ─── 15. 3-1-3 ───────────────────────────────────────────────
INSERT INTO formations (name, type, description, how_to_play, how_to_attack_against, how_to_defend_against, strengths, weaknesses, best_counter_formations, key_player_roles, famous_teams, radar_stats, player_positions)
VALUES (
  '3-1-3',
  '8',
  'Le 3-1-3 est la formation la plus offensive et spectaculaire du football à 8. Avec un seul milieu défensif et un trio offensif haut, cette formation vise à écraser l''adversaire dans sa zone de jeu dès le coup d''envoi. Idéale pour les équipes avec une qualité technique supérieure, elle est risquée mais terriblement efficace quand les joueurs ont le niveau pour la pratiquer.',
  'Le trio offensif reste haut et large pour étirer la défense adverse sur toute la largeur du terrain. Le milieu central unique est le joueur le plus important : il doit à la fois récupérer les ballons perdus, relancer et parfois soutenir l''attaque. Les 3 défenseurs forment une ligne compacte mais haute, permettant à l''équipe de jouer dans la moitié adverse en permanence. En phase de possession, le ballon circule rapidement sur les 3 attaquants pour trouver le déséquilibre.',
  'Pour attaquer un 3-1-3, le milieu adverse est en 1v... plusieurs. Surcharger le milieu adverse unique en créant des 2v1 ou 3v1 crée des transitions rapides vers le but. Les contre-attaques sont également efficaces : avec les 3 attaquants adverses haut et 3 défenseurs dos au but, une transition rapide peut créer une situation 3v3 favorable.',
  'Défendre contre un 3-1-3 nécessite de neutraliser le milieu adverse unique. Si on l''isole et qu''on récupère le ballon dans la zone médiane, des contre-attaques à 3 ou 4 contre 3 adverses sont possibles. La clé est d''être discipliné défensivement et d''attendre les opportunités de récupération.',
  '["Formation ultra-offensive — pression permanente sur la défense", "Trio offensif très difficile à défendre pour une défense à 3", "Football spectaculaire et attractif", "Idéale pour les équipes très techniques", "Psychologiquement dominante — l''adversaire subit"]',
  '["Le milieu seul peut être débordé en 3v1 facilement", "Défense à 3 vulnérable aux transitions rapides", "Formation très risquée si le milieu unique est éliminé", "Exige un trio offensif de très haute qualité", "Difficile à pratiquer sur terrain humide ou terrain réduit"]',
  '["3-3-1 (compact)", "4-2-1", "3-2-2"]',
  '{"GK": "Gardien de haut niveau — dernier rempart sur de nombreuses contre-attaques", "CB-R": "Défenseur droit : fort en 1v1, prend des risques mesurés", "CB-C": "Défenseur central : libero vocal et expérimenté", "CB-L": "Défenseur gauche : couverture côté gauche", "CM": "LE milieu — le joueur le plus important : athlète complet, récupérateur et distributeur", "RW": "Ailier droit : vitesse, dribble, finition", "CF": "Avant-centre : pivot, combine avec les ailiers, finisseur", "LW": "Ailier gauche : percussion, rentre dans l''axe pour frapper"}',
  '["Équipes U13-U15 très techniques", "Académies de football formateur", "Football récréatif offensive entre amis"]',
  '{"attack": 90, "defense": 52, "pressing": 85, "possession": 62, "transition": 85}',
  '[{"id":"GK","label":"GB","x":0.5,"y":0.95},{"id":"CB-R","label":"DD","x":0.72,"y":0.82},{"id":"CB-C","label":"DC","x":0.5,"y":0.85},{"id":"CB-L","label":"DG","x":0.28,"y":0.82},{"id":"CM","label":"MC","x":0.5,"y":0.58},{"id":"RW","label":"AD","x":0.8,"y":0.22},{"id":"CF","label":"BU","x":0.5,"y":0.15},{"id":"LW","label":"AG","x":0.2,"y":0.22}]'
);
